    memset(d, -1, sizeof(d));
    for (int i = 0; i < n; ++i) {
        d[i][s] = 0;
        pq.emplace(0, i, s);
    }

    while (!pq.empty()) {
        auto [cost, pos, mask] = pq.top();
        pq.pop();

        if (d[pos][mask] != -1 && d[pos][mask] <= cost) continue;

        for (int i = 0; i < n; ++i) {
